var PARTNERS_ACTIVE_TAB='inquiries';var PARTNERS_TIERS_CACHE=[];document.addEventListener('click',function(ev){var btn=ev.target.closest('.partners-subtab');if(!btn)return;var tab=btn.getAttribute('data-partners-tab');if(!tab||tab===PARTNERS_ACTIVE_TAB)return;PARTNERS_ACTIVE_TAB=tab;document.querySelectorAll('.partners-subtab').forEach(function(b){var on=b.getAttribute('data-partners-tab')===tab;b.style.background=on?'rgba(122,194,49,.12)':'transparent';b.style.color=on?'#7AC231':'#888';b.style.borderColor=on?'rgba(122,194,49,.3)':'#2a2a2a';b.classList.toggle('active',on);});document.querySelectorAll('.partners-pane').forEach(function(p){p.style.display=(p.id==='partners-pane-'+tab)?'':'none';});if(tab==='inquiries')loadPartnerInquiries();else if(tab==='tiers')loadPartnerTiers();else if(tab==='directory')loadPartnerDirectory();});function loadPartnerInquiries(){var status=(document.getElementById('partnersInquiryFilter')||{}).value||'';var url=ATP_API+'/partners/admin/inquiries'+(status?'?status='+encodeURIComponent(status):'');fetch(url,{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderPartnerInquiries((data&&data.inquiries)||[]);}).catch(function(){document.getElementById('partnerInquiriesList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load inquiries.</div>';});}
function renderPartnerInquiries(list){var el=document.getElementById('partnerInquiriesList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center;font-size:13px">No inquiries yet. Once a brand submits the form on /partners, leads land here.</div>';var badge=document.getElementById('adminPartnersBadge');if(badge)badge.style.display='none';return;}
var newCount=list.filter(function(i){return i.status==='new';}).length;var badge=document.getElementById('adminPartnersBadge');if(badge){if(newCount>0){badge.textContent=newCount+' new';badge.style.display='';}else{badge.style.display='none';}}
var statusColors={new:{bg:'rgba(245,158,11,.15)',fg:'#fbbf24',border:'rgba(245,158,11,.4)'},contacted:{bg:'rgba(96,165,250,.15)',fg:'#93c5fd',border:'rgba(96,165,250,.4)'},qualified:{bg:'rgba(122,194,49,.15)',fg:'#7AC231',border:'rgba(122,194,49,.4)'},won:{bg:'rgba(122,194,49,.3)',fg:'#a8e055',border:'rgba(122,194,49,.6)'},lost:{bg:'rgba(239,68,68,.15)',fg:'#fca5a5',border:'rgba(239,68,68,.4)'},};el.innerHTML=list.map(function(i){var color=statusColors[i.status]||statusColors.new;var when=i.created_at?new Date(i.created_at).toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})+' · '+new Date(i.created_at).toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'}):'';var name=(i.contact_name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var email=(i.contact_email||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var company=(i.company||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var msg=(i.message||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/\n/g,'<br>');return'<div style="background:#0d0d0d;border:1px solid #222;border-left:3px solid '+color.border+';border-radius:10px;padding:18px;margin-bottom:10px">'+'<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:14px;margin-bottom:10px;flex-wrap:wrap">'+'<div>'+'<div style="font-size:15px;font-weight:700;color:#fff;margin-bottom:3px">'+name+
(company?' <span style="font-weight:500;color:#888;font-size:13px">· '+company+'</span>':'')+'</div>'+'<div style="font-size:12px;color:#888"><a href="mailto:'+email+'" style="color:#7AC231">'+email+'</a>'+
(i.contact_phone?' · '+i.contact_phone:'')+'</div>'+'</div>'+'<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">'+'<span style="font-size:11px;color:#666">'+when+'</span>'+'<select onchange="updateInquiryStatus(\''+i.id+'\', this.value)" style="background:'+color.bg+';color:'+color.fg+';border:1px solid '+color.border+';border-radius:20px;padding:4px 10px;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;cursor:pointer">'+
['new','contacted','qualified','won','lost'].map(function(s){return'<option value="'+s+'"'+(s===i.status?' selected':'')+'>'+s+'</option>';}).join('')+'</select>'+'</div>'+'</div>'+'<div style="display:flex;gap:14px;flex-wrap:wrap;font-size:12px;color:#aaa;margin-bottom:'+(msg?'12px':'0')+'">'+
(i.tier_name?'<span>📦 <strong style="color:#fff">'+i.tier_name+'</strong></span>':'')+
(i.brand_size?'<span>👥 '+i.brand_size+'</span>':'')+
(i.budget_band?'<span>💰 '+i.budget_band+'</span>':'')+'</div>'+
(msg?'<div style="font-size:13px;color:#ddd;line-height:1.6;padding:12px;background:#161616;border-radius:6px">'+msg+'</div>':'')+'</div>';}).join('');}
function updateInquiryStatus(id,status){fetch(ATP_API+'/partners/admin/inquiries/'+id,{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify({status:status}),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Status updated');loadPartnerInquiries();});}
function loadPartnerTiers(){fetch(ATP_API+'/partners/admin/tiers',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){PARTNERS_TIERS_CACHE=(data&&data.tiers)||[];renderPartnerTiers(PARTNERS_TIERS_CACHE);_populatePartnerDirTierSelect();});}
function renderPartnerTiers(list){var el=document.getElementById('partnerTiersList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center">No tiers yet. Run /api/auth/migrate-partners to seed the defaults, or add one above.</div>';return;}
el.innerHTML=list.map(function(t){var price=parseInt(t.monthly_price_cents,10)||0;var ccy=(t.currency||'aed').toUpperCase();var priceTxt=price===0?'Custom pricing':ccy+' '+(price/100).toLocaleString()+' / month';var perks=Array.isArray(t.perks)?t.perks:(typeof t.perks==='string'?(function(){try{return JSON.parse(t.perks);}catch(e){return[];}})():[]);var name=(t.name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var status=t.is_active?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(122,194,49,.15);color:#7AC231">Active</span>':'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(255,255,255,.06);color:#666">Off</span>';var featured=t.is_featured?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(245,158,11,.18);color:#fbbf24;border:1px solid rgba(245,158,11,.4)">★ Featured</span>':'';return'<div style="background:#0d0d0d;border:1px solid #222;border-radius:10px;padding:18px;margin-bottom:10px">'+'<div style="display:flex;justify-content:space-between;gap:14px;margin-bottom:10px;flex-wrap:wrap">'+'<div>'+'<div style="display:flex;gap:8px;align-items:center;margin-bottom:4px">'+'<span style="font-size:15px;font-weight:700;color:#fff">'+name+'</span>'+
featured+status+'</div>'+'<div style="font-size:13px;color:#7AC231;font-weight:600">'+priceTxt+'</div>'+
(t.tagline?'<div style="font-size:12px;color:#888;margin-top:4px">'+t.tagline.replace(/</g,'&lt;')+'</div>':'')+'</div>'+'<div style="display:flex;gap:6px;align-items:flex-start">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px" data-atp-call="editPartnerTier" data-args=\'["'+t.id+'"]\'>Edit</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deletePartnerTier" data-args=\'["'+t.id+'"]\'>Deactivate</button>'+'</div>'+'</div>'+
(perks.length?'<ul style="margin:8px 0 0 18px;padding:0;font-size:12px;color:#bbb;line-height:1.7">'+
perks.map(function(p){return'<li>'+(p||'').replace(/</g,'&lt;')+'</li>';}).join('')+'</ul>':'')+'</div>';}).join('');}
function newPartnerTier(){['ptEditId','ptName','ptTagline','ptDescription','ptPerks','ptCta'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('ptPrice').value=0;document.getElementById('ptSort').value=100;document.getElementById('ptFeatured').checked=false;document.getElementById('ptActive').checked=true;document.getElementById('partnerTierFormWrap').style.display='block';document.getElementById('ptName').focus();}
function editPartnerTier(e,btn){var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];var t=PARTNERS_TIERS_CACHE.find(function(x){return x.id===id;});if(!t)return;document.getElementById('ptEditId').value=t.id;document.getElementById('ptName').value=t.name||'';document.getElementById('ptTagline').value=t.tagline||'';document.getElementById('ptDescription').value=t.description||'';document.getElementById('ptPrice').value=t.monthly_price_cents||0;document.getElementById('ptSort').value=t.sort_order||100;var perks=Array.isArray(t.perks)?t.perks:(typeof t.perks==='string'?(function(){try{return JSON.parse(t.perks);}catch(e){return[];}})():[]);document.getElementById('ptPerks').value=perks.join('\n');document.getElementById('ptCta').value=t.cta_label||'';document.getElementById('ptFeatured').checked=!!t.is_featured;document.getElementById('ptActive').checked=!!t.is_active;document.getElementById('partnerTierFormWrap').style.display='block';}
function cancelPartnerTierForm(){document.getElementById('partnerTierFormWrap').style.display='none';}
function savePartnerTier(){var id=document.getElementById('ptEditId').value;var perksRaw=document.getElementById('ptPerks').value||'';var perks=perksRaw.split(/\r?\n/).map(function(s){return s.trim();}).filter(Boolean);var body={name:(document.getElementById('ptName').value||'').trim(),tagline:(document.getElementById('ptTagline').value||'').trim()||null,description:(document.getElementById('ptDescription').value||'').trim()||null,monthly_price_cents:parseInt(document.getElementById('ptPrice').value,10)||0,perks:perks,sort_order:parseInt(document.getElementById('ptSort').value,10)||100,cta_label:(document.getElementById('ptCta').value||'').trim()||null,is_featured:document.getElementById('ptFeatured').checked,is_active:document.getElementById('ptActive').checked,};if(!body.name){showToast('Name required',true);return;}
var url=id?(ATP_API+'/partners/admin/tiers/'+id):(ATP_API+'/partners/admin/tiers');fetch(url,{method:id?'PATCH':'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Tier updated':'✅ Tier created');cancelPartnerTierForm();loadPartnerTiers();});}
function deletePartnerTier(e,btn){if(!confirm('Deactivate this tier? It will hide from the /partners page; existing inquiries that reference it keep their tier name.'))return;var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];fetch(ATP_API+'/partners/admin/tiers/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Tier deactivated');loadPartnerTiers();});}
var PARTNERS_DIR_CACHE=[];function loadPartnerDirectory(){fetch(ATP_API+'/partners/admin/directory',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){PARTNERS_DIR_CACHE=(data&&data.partners)||[];renderPartnerDirectory(PARTNERS_DIR_CACHE);});}
function _populatePartnerDirTierSelect(){var sel=document.getElementById('pdTier');if(!sel)return;sel.innerHTML='<option value="">No tier</option>'+
PARTNERS_TIERS_CACHE.map(function(t){return'<option value="'+t.id+'">'+(t.name||'').replace(/</g,'&lt;')+'</option>';}).join('');}
function renderPartnerDirectory(list){var el=document.getElementById('partnerDirectoryList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:30px;color:#555;text-align:center">No partners in the directory yet. Add one above to populate the logo strip on /partners.</div>';return;}
el.innerHTML='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px">'+
list.map(function(p){var status=p.is_active?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(122,194,49,.15);color:#7AC231">Active</span>':'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(255,255,255,.06);color:#666">Off</span>';var name=(p.name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;');var logoBlock=p.logo_url?'<img loading="lazy" src="'+p.logo_url.replace(/"/g,'&quot;')+'" alt="" style="max-height:40px;max-width:100%;object-fit:contain;margin-bottom:8px;filter:brightness(1.3)">':'<div style="font-family:var(--ff-display, Barlow Condensed);font-size:18px;font-weight:800;color:#888;margin-bottom:8px">'+name+'</div>';return'<div style="background:#0d0d0d;border:1px solid #222;border-radius:10px;padding:16px">'+
logoBlock+'<div style="display:flex;justify-content:space-between;align-items:center;gap:8px;margin-bottom:6px">'+'<span style="font-size:14px;font-weight:700;color:#fff">'+name+'</span>'+
status+'</div>'+
(p.tier_name?'<div style="font-size:11px;color:#7AC231;margin-bottom:6px">'+p.tier_name+'</div>':'')+
(p.testimonial?'<div style="font-size:11px;color:#888;font-style:italic;margin-bottom:8px;line-height:1.5">"'+(p.testimonial||'').slice(0,80).replace(/</g,'&lt;')+(p.testimonial.length>80?'…':'')+'"</div>':'')+'<div style="display:flex;gap:6px">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px;flex:1" data-atp-call="editPartnerDirectory" data-args=\'["'+p.id+'"]\'>Edit</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deletePartnerDirectory" data-args=\'["'+p.id+'"]\'>×</button>'+'</div>'+'</div>';}).join('')+'</div>';}
function newPartnerDirectory(){['pdEditId','pdName','pdLogo','pdWebsite','pdBlurb','pdQuote','pdQuoteAttr'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('pdSort').value=100;document.getElementById('pdTier').value='';document.getElementById('pdFeatured').checked=false;document.getElementById('pdActive').checked=true;_populatePartnerDirTierSelect();document.getElementById('partnerDirFormWrap').style.display='block';document.getElementById('pdName').focus();}
function editPartnerDirectory(e,btn){var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];var p=PARTNERS_DIR_CACHE.find(function(x){return x.id===id;});if(!p)return;document.getElementById('pdEditId').value=p.id;document.getElementById('pdName').value=p.name||'';document.getElementById('pdLogo').value=p.logo_url||'';document.getElementById('pdWebsite').value=p.website_url||'';document.getElementById('pdBlurb').value=p.blurb||'';document.getElementById('pdQuote').value=p.testimonial||'';document.getElementById('pdQuoteAttr').value=p.testimonial_attribution||'';document.getElementById('pdSort').value=p.sort_order||100;document.getElementById('pdFeatured').checked=!!p.is_featured;document.getElementById('pdActive').checked=!!p.is_active;_populatePartnerDirTierSelect();if(p.tier_id)document.getElementById('pdTier').value=p.tier_id;document.getElementById('partnerDirFormWrap').style.display='block';}
function cancelPartnerDirectoryForm(){document.getElementById('partnerDirFormWrap').style.display='none';}
function savePartnerDirectory(){var id=document.getElementById('pdEditId').value;var body={name:(document.getElementById('pdName').value||'').trim(),logo_url:(document.getElementById('pdLogo').value||'').trim()||null,website_url:(document.getElementById('pdWebsite').value||'').trim()||null,tier_id:document.getElementById('pdTier').value||null,blurb:(document.getElementById('pdBlurb').value||'').trim()||null,testimonial:(document.getElementById('pdQuote').value||'').trim()||null,testimonial_attribution:(document.getElementById('pdQuoteAttr').value||'').trim()||null,sort_order:parseInt(document.getElementById('pdSort').value,10)||100,is_featured:document.getElementById('pdFeatured').checked,is_active:document.getElementById('pdActive').checked,};if(!body.name){showToast('Name required',true);return;}
var url=id?(ATP_API+'/partners/admin/directory/'+id):(ATP_API+'/partners/admin/directory');fetch(url,{method:id?'PATCH':'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Partner updated':'✅ Partner added');cancelPartnerDirectoryForm();loadPartnerDirectory();});}
function deletePartnerDirectory(e,btn){if(!confirm('Remove this partner from the directory? Their logo will disappear from /partners immediately.'))return;var id=JSON.parse(btn.getAttribute('data-args')||'[]')[0];fetch(ATP_API+'/partners/admin/directory/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Partner removed');loadPartnerDirectory();});}